VALUES
  ('islands-6f0ba476-moex-00034', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲向乙承租樓房一層供家人居住。下列敘述何者錯誤？', '["當甲於該屋內因抽象輕過失烹煮不慎，致房屋全部燒燬，則甲不須對乙負賠償責任", "當甲之子丙於該屋因重大過失燃放火燭不慎，致房屋部分燒燬，則甲不須對乙負賠償責任", "當甲將該屋之部分轉租與丁，丁於該屋因重大過失燃放火燭不慎，致該屋部分燒燬，則甲須對 乙負賠償責任", "當因甲之疏失致甲向乙承租之該屋被戊侵占使用，戊於使用中因抽象輕過失烹煮不慎，致房屋 部分燒燬，則甲須對乙負賠償責任 60440"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00035', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲趁離職休息，報名參加乙旅行社規劃之東非原野之旅。下列關於旅遊契約之敘述，何者錯誤？', '["若甲於出發前 1 個月，因車禍骨折須休養及復健，欲變更由其甫自研究所畢業之妹丙參加旅 遊。如因丙為旅客而減少費用，旅客不得請求退還", "若旅遊當地遭暴雨侵襲，致巴士無法涉水通過原訂路線，則乙旅行社得變更旅遊內容，但因此 所增加之費用，不得向旅客收取", "若甲自行外出，路過當地A紀念品店購入一手工燭台，而該燭台於返臺隔日即因瑕疵斷裂，則 甲得請求乙旅行社協助處理", "若甲於旅遊中，違反指示將手臂伸出車窗外，致遭飛禽啄傷，則乙旅行社應為必要之協助及處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00036', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於懸賞廣告之敘述，何者錯誤？', '["懸賞廣告為單獨行為", "廣告人對於完成廣告所定行為之人有給付報酬之義務", "數人先後分別完成廣告所定行為時，原則上由最先完成該行為之人，取得報酬請求權", "不知有廣告而完成廣告所定行為之人，仍享有報酬請求權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00037', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於委任之敘述，何者正確？', '["受任人受概括委任時，為委任人買入不動產，不須有特別之授權", "受任人因有不得已之事由，使第三人代為處理委任事務時，就該第三人之行為，與就自己之行 為，負同一責任", "委任關係因非可歸責於受任人之事由，於事務處理未完畢前已終止者，除當事人間有相反之特 約存在外，受任人不得請求任何報酬", "委任人得將處理委任事務之請求權，任意讓與第三人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00038', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲騎腳踏車違反紅燈號誌，致與綠燈直行之乙機車騎士發生碰撞，乙得對甲求償之時效為何？', '["自請求權人知有損害及賠償義務人時起2年", "自請求權人知有損害時起2年", "自請求權人知有賠償義務人時起2年", "自請求權得行使時起15年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00039', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於民法第184條第1項前段侵權行為規定之敘述，何者錯誤？', '["對擔保標的物之毀損、滅失，構成侵害擔保物權之侵權行為", "純粹經濟上損失，非屬民法第184條第1項前段所定之適用對象", "二重買賣之故意後買受人，原則上就先買受人債權非屬民法第184條第1項前段所定之適用對象", "因第三人故意毀損特定物買賣之標的，致出賣人免給付義務，第三人構成民法第184條第1項 前段之買受人人格權之侵害"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00040', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '物權之取得，可能依法律規定，亦可能依物權行為。下列何者並非依法律規定取得之物權？', '["受讓人善意取得動產所有權", "無權占有人時效取得動產所有權", "承攬人就定作人因承攬工作所交付之動產，取得動產留置權", "分別共有人依協議分割，取得分得部分之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00041', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '依民法規定，抵押權不得由債權分離而為讓與，或為其他債權之擔保。此乃普通抵押權之何種 特性？', '["優先受償性", "不可分性", "從屬性", "物上代位性 60440"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00042', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '甲向乙借款新臺幣（下同）500萬元，為擔保借款，甲委請丙出面為其借款擔任全額清償之連帶 保證人，並由丁提供價值1000萬A地設定全額抵押權於乙。嗣後甲無資力清償，且財產經強制 執行而無效果。關於乙之500萬確保，下列敘述何者錯誤？', '["乙得先向抵押人丁請求償還", "乙得先向保證人丙請求償還，丙不得以先訴抗辯權抗辯", "若乙先向抵押人丁請求償還，丁於向乙為全額清償後，得轉對保證人丙請求償還500萬", "若丁向乙為全額清償後未為內部求償，得向主債務人甲主張償還500萬"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('islands-6f0ba476-moex-00043', 'islands-6f0ba476', 'islands-6f0ba476-moex-114-a7c7609b', 'sub-islands-6f0ba476-02', NULL, 'single_choice', '下列關於共有之敘述，何者錯誤？', '["共有物之簡易修繕及其他保存行為，得由各共有人單獨為之", "共有物，除契約另有約定外，應由全體共有人同意管理之", "動產共有物之處分、變更及設定負擔，應得全體共有人之同意", "應有部分之處分，各共有人得自由為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:58+00:00", "source_pdf_sha1": "0145a0501847", "answer_pdf_sha1": "92adf14b3e43", "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "415", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "財稅行政"}'::jsonb, NULL)
